                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.totalElements").value(2))
                    .andExpect(jsonPath("$.content[*].title",
                            everyItem(containsStringIgnoringCase("backend"))));
        }

        @Test
        @DisplayName("AC12: priority filter returns only matching tasks")
        void listTasks_priorityFilter() throws Exception {
            createTaskAndGetId("High Task 1", null, "HIGH");
            createTaskAndGetId("Low Task", null, "LOW");
            createTaskAndGetId("High Task 2", null, "HIGH");

            mockMvc.perform(get("/api/tasks")
                            .param("priority", "HIGH")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.totalElements").value(2))
                    .andExpect(jsonPath("$.content[*].priority",
                            everyItem(is("HIGH"))));
        }

        @Test
        @DisplayName("AC13: page=1&size=5 returns correct second page")
        void listTasks_pagination() throws Exception {
            // Create 8 tasks
            for (int i = 1; i <= 8; i++) {
                createTaskAndGetId("Paged Task " + i, null, null);
            }

            mockMvc.perform(get("/api/tasks")
                            .param("page", "1")
                            .param("size", "5")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.page").value(1))
                    .andExpect(jsonPath("$.size").value(5))
                    .andExpect(jsonPath("$.totalElements").value(8))
                    .andExpect(jsonPath("$.totalPages").value(2))
                    .andExpect(jsonPath("$.content.length()").value(3));
        }

        @Test
        @DisplayName("AC14: no token returns 401")
        void listTasks_noToken_returns401() throws Exception {
            mockMvc.perform(get("/api/tasks"))
                    .andExpect(status().isUnauthorized());
        }

        @Test
        @DisplayName("empty list returns page with 0 elements")
        void listTasks_empty_returnsEmptyPage() throws Exception {
            mockMvc.perform(get("/api/tasks")
                            .header("Authorization", "Bearer " + token))
                    .andExpect(status().isOk())
                    .andExpect(jsonPath("$.totalElements").value(0))
                    .andExpect(jsonPath("$.content").isArray())
                    .andExpect(jsonPath("$.content.length()").value(0));
        }
    }
